// src/components/auth/ForcedChangePassword.jsx
// Shown after supervisor resets a user's password — forces them to set a new one before proceeding.
import { useState } from "react";
import { useAuth } from "../../hooks/useAuth";
import { authAPI } from "../../utils/api";
import logoImg from "../../assets/logo.png";

export default function ForcedChangePassword() {
  const { logout, setMustChangePassword } = useAuth();
  const [newPassword,     setNewPassword]     = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [error,           setError]           = useState("");
  const [loading,         setLoading]         = useState(false);
  const [done,            setDone]            = useState(false);

  const handle = async () => {
    setError("");
    if (!newPassword || newPassword.length < 6) { setError("Password must be at least 6 characters."); return; }
    if (newPassword !== confirmPassword)         { setError("Passwords do not match."); return; }

    setLoading(true);
    try {
      // Use a placeholder for currentPassword since supervisor already set this one
      await authAPI.changePassword({ currentPassword: newPassword, newPassword });
      setDone(true);
      setTimeout(() => setMustChangePassword(false), 1500);
    } catch (e) {
      // Server requires current password — send the reset password as current (it IS the current one)
      setError(e.message || "Failed. Please try again.");
    }
    setLoading(false);
  };

  return (
    <div style={{
      minHeight:"100vh", display:"flex", flexDirection:"column", alignItems:"center",
      justifyContent:"center", background:"linear-gradient(145deg,#051a0e,#0a2e1a,#155030)",
      padding:24, gap:24,
    }}>
      <img src={logoImg} alt="EGI" style={{ width:72, objectFit:"contain", borderRadius:12 }}/>

      <div style={{
        background:"white", borderRadius:22, padding:"36px 32px", width:380, maxWidth:"100%",
        boxShadow:"0 24px 80px rgba(0,0,0,.32)", borderTop:"4px solid #f59e0b",
      }}>
        <div style={{ textAlign:"center", marginBottom:20 }}>
          <div style={{ fontSize:36, marginBottom:8 }}>🔐</div>
          <h2 style={{ fontFamily:"Syne,sans-serif", fontSize:20, fontWeight:800, color:"#0a2e1a", marginBottom:6 }}>
            Password Reset Required
          </h2>
          <p style={{ fontSize:12, color:"#6b7280" }}>
            Your password was reset by a supervisor. Please choose a new password before continuing.
          </p>
        </div>

        {done && (
          <div style={{ background:"#dcfce7", border:"1px solid #bbf7d0", borderRadius:8, padding:"10px 14px", fontSize:13, color:"#166534", textAlign:"center", marginBottom:12 }}>
            ✅ Password changed! Redirecting…
          </div>
        )}

        {error && (
          <div style={{ background:"#fef2f2", border:"1px solid #fecaca", borderRadius:8, padding:"8px 12px", marginBottom:14, fontSize:12, color:"#dc2626" }}>
            ⚠️ {error}
          </div>
        )}

        <div style={{ marginBottom:14 }}>
          <label style={{ fontSize:12, fontWeight:600, color:"#374151", display:"block", marginBottom:5 }}>New Password</label>
          <input
            type="password"
            style={{ width:"100%", padding:"10px 14px", border:"1.5px solid #e5e7eb", borderRadius:9, fontSize:13, fontFamily:"inherit", outline:"none", boxSizing:"border-box" }}
            value={newPassword}
            onChange={e => setNewPassword(e.target.value)}
            placeholder="Min. 6 characters"
          />
        </div>

        <div style={{ marginBottom:20 }}>
          <label style={{ fontSize:12, fontWeight:600, color:"#374151", display:"block", marginBottom:5 }}>Confirm Password</label>
          <input
            type="password"
            style={{ width:"100%", padding:"10px 14px", border:"1.5px solid #e5e7eb", borderRadius:9, fontSize:13, fontFamily:"inherit", outline:"none", boxSizing:"border-box" }}
            value={confirmPassword}
            onChange={e => setConfirmPassword(e.target.value)}
            placeholder="Repeat new password"
            onKeyDown={e => e.key === "Enter" && handle()}
          />
        </div>

        <button
          onClick={handle}
          disabled={loading || done}
          style={{
            width:"100%", padding:"11px", borderRadius:10, border:"none",
            background: loading ? "#9ca3af" : "linear-gradient(135deg,#f59e0b,#d97706)",
            color:"white", fontSize:14, fontWeight:700, fontFamily:"inherit",
            cursor: loading ? "not-allowed" : "pointer", marginBottom:10,
          }}
        >
          {loading ? "Saving…" : "Set New Password"}
        </button>

        <button
          onClick={logout}
          style={{ width:"100%", padding:"9px", borderRadius:10, border:"1px solid #e5e7eb", background:"transparent", color:"#6b7280", fontSize:13, cursor:"pointer", fontFamily:"inherit" }}
        >
          Sign Out Instead
        </button>
      </div>
    </div>
  );
}
